          message:
            typeof event.data.message === "string"
              ? event.data.message
              : "Generated module crashed.",
        });
      }
    }

    window.addEventListener("message", handleMessage);
    return () => window.removeEventListener("message", handleMessage);
  }, [onStatusChange, pack]);

  return (
